@typeparam TItem
@implements IAsyncDisposable

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="sentinelRef" class="infinite-scroll-sentinel">
            @if (isLoading)
            {
                <div class="infinite-scroll-spinner"></div>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    [Parameter]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Inject]
    private IJSRuntime JS { get; set; } = default!;

    private ElementReference sentinelRef;
    private IJSObjectReference? module;
    private IJSObjectReference? observer;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? dotnetRef;
    private bool isLoading;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-96ef09c4764e40b38976a8282c9a7376/Components/InfiniteScrollList.razor.js");
        }

        if (HasMore && module is not null)
        {
            // Re-observe after each render since the sentinel element may be re-created.
            if (observer is not null)
            {
                await module.InvokeVoidAsync("dispose", observer);
            }

            dotnetRef?.Dispose();
            dotnetRef = DotNetObjectReference.Create(this);
            observer = await module.InvokeAsync<IJSObjectReference>(
                "initialize", sentinelRef, dotnetRef);
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (isLoading || !HasMore)
            return;

        isLoading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        isLoading = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (observer is not null && module is not null)
        {
            try
            {
                await module.InvokeVoidAsync("dispose", observer);
            }
            catch (JSDisconnectedException) { }
        }

        dotnetRef?.Dispose();

        if (module is not null)
        {
            try
            {
                await module.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
    }
}

